DROP TABLE IF EXISTS `IE_004_406_INC`;
CREATE TABLE `IE_004_406_INC` (
  `SENSITIVEFLAG`          VARCHAR(30)      DEFAULT NULL COMMENT '涉密标志',
  `GSFZJG`                 VARCHAR(200)     DEFAULT NULL COMMENT '归属分支机构',
  `DGCKZH`                 VARCHAR(60)      DEFAULT NULL COMMENT '对公存款账号；PK。关联数据项：对公存款分户账.对公存款账号',
  `JYLX`                   VARCHAR(60)      DEFAULT NULL COMMENT '交易类型',
  `HXJYRQ`                 VARCHAR(8)       DEFAULT NULL COMMENT '核心交易日期；PK。本笔交易在核心系统的交易日期。',
  `BZ`                     VARCHAR(3)       DEFAULT NULL COMMENT '币种',
  `ZHYE`                   DECIMAL(20,2)    DEFAULT NULL COMMENT '账户余额；本笔交易时点完成后该时点的账户余额。',
  `DFHM`                   VARCHAR(450)     DEFAULT NULL COMMENT '对方户名；客户往账业务对应传票上记载的最终交易对手信息。1. 现转标志为“转”时，交易对手信息必填，不可为空。2. 该笔明细交易是转账交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户。3. 交易对手是第三方支付平台账号的，对方账号填报为交易对手第三方支付账号，对方户名填报为交易对手的第三方支付户名，对方行名填报为第三方支付平台名称，对方行号允许为空。4. 对于代收、代扣、代缴等交易的，对方账号和对方户名必须填实际收款人或付款人，不可填中间过渡账户或清算账户；对于代发等代付业务，交易对手为多个的，允许交易对手可以登记为中间过渡账户。5. 对方账号与对方户名必须一致，对应同一实体。6. 若对方账户是境内银行机构开立的账户，则对方行号必须是12位人行支付行号，对方行名必须是与人行支付行号对应的银行机构名称。分支机构如没有人行支付行号，可填写最近的上一级管理机构支付行号。各行应从官方渠道获得一份官方发布的人行支付行号及行名字典表，确保对方行号填写的人行支付行号与对方行名保持一致。7. 贷款还息、贷款还本、手续费、系统转存等交易，交易对手填实际转入的信贷分户账或内部分户账，并在摘要中注明，不可为空。',
  `DFXH`                   VARCHAR(30)      DEFAULT NULL COMMENT '对方行号；客户往账业务对应传票上记载的最终交易对手信息。1. 现转标志为“转”时，交易对手信息必填，不可为空。2. 该笔明细交易是转账交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户。3. 交易对手是第三方支付平台账号的，对方账号填报为交易对手第三方支付账号，对方户名填报为交易对手的第三方支付户名，对方行名填报为第三方支付平台名称，对方行号允许为空。4. 对于代收、代扣、代缴等交易的，对方账号和对方户名必须填实际收款人或付款人，不可填中间过渡账户或清算账户；对于代发等代付业务，交易对手为多个的，允许交易对手可以登记为中间过渡账户。5. 对方账号与对方户名必须一致，对应同一实体。6. 若对方账户是境内银行机构开立的账户，则对方行号必须是12位人行支付行号，对方行名必须是与人行支付行号对应的银行机构名称。分支机构如没有人行支付行号，可填写最近的上一级管理机构支付行号。各行应从官方渠道获得一份官方发布的人行支付行号及行名字典表，确保对方行号填写的人行支付行号与对方行名保持一致。7. 贷款还息、贷款还本、手续费、系统转存等交易，交易对手填实际转入的信贷分户账或内部分户账，并在摘要中注明，不可为空。',
  `CBMBZ`                  VARCHAR(9)       DEFAULT NULL COMMENT '冲补抹标志；冲正，补账，抹账交易统一填报“冲补抹”。',
  `XZBZ`                   VARCHAR(3)       DEFAULT NULL COMMENT '现转标志；把现金交易识别出来放入“现”，其他都放入“转”。',
  `IPDZ`                   VARCHAR(40)      DEFAULT NULL COMMENT 'IP地址；若交易渠道为网银、手机银行，填写交易发起终端的IP地址。其他情况允许为空。',
  `SQGYH`                  VARCHAR(30)      DEFAULT NULL COMMENT '授权柜员号；关联数据项：柜员表.柜员号，无需授权的柜员号允许为空。',
  `CJRQ`                   VARCHAR(8)       DEFAULT NULL COMMENT '采集日期；PK。采集日期指该期（批次）数据报送的期末日期，例如：按日采集的表，采集日期应为每日；按月采集的表，采集日期应为月末最后一天；以此类推。有特殊报送要求的，应以报送要求的截至日期为采集日期。',
  `JRXKZH`                 VARCHAR(30)      DEFAULT NULL COMMENT '金融许可证号；填报账户归属的银行机构。营业机构、管理机构必须填报“金融许可证号”，内设机构、虚拟机构及营业部取本级或上一级管理机构的金融许可证号，优先取本级。',
  `YHJGMC`                 VARCHAR(450)     DEFAULT NULL COMMENT '银行机构名称；填报账户归属的银行机构。关联数据项：机构信息表.银行机构名称',
  `JYXLH`                  VARCHAR(100)     DEFAULT NULL COMMENT '交易序列号；PK。',
  `NBJGH`                  VARCHAR(30)      DEFAULT NULL COMMENT '内部机构号；填报账户归属的银行机构。关联数据项：机构信息表.内部机构号',
  `YWBLJGH`                VARCHAR(30)      DEFAULT NULL COMMENT '业务办理机构号；填报办理业务的银行机构。关联数据项：机构信息表.内部机构号',
  `MXKMBH`                 VARCHAR(60)      DEFAULT NULL COMMENT '明细科目编号；同一条数据涉及多个明细科目的，仅填报该笔业务指向的主要科目，如：一笔贷款仅包含正常本金时，填报正常本金科目，如一笔贷款既包含正常本金也包含逾期本金时，填报逾期本金科目。关联数据项：总账会计全科目表.会计科目编号。',
  `MXKMMC`                 VARCHAR(300)     DEFAULT NULL COMMENT '明细科目名称；同一条数据涉及多个明细科目的，仅填报该笔业务指向的主要科目，如：一笔贷款仅包含正常本金时，填报正常本金科目，如一笔贷款既包含正常本金也包含逾期本金时，填报逾期本金科目。关联数据项：总账会计全科目表.会计科目编号。',
  `KHTYBH`                 VARCHAR(70)      DEFAULT NULL COMMENT '客户统一编号；关联数据项：对公客户信息表.客户统一编号',
  `WBZH`                   VARCHAR(60)      DEFAULT NULL COMMENT '外部账号',
  `JYJDBZ`                 VARCHAR(3)       DEFAULT NULL COMMENT '交易借贷标志',
  `HXJYSJ`                 VARCHAR(6)       DEFAULT NULL COMMENT '核心交易时间；PK。本笔交易在核心系统的交易时间。',
  `JYJE`                   DECIMAL(20,2)    DEFAULT NULL COMMENT '交易金额',
  `DFZH`                   VARCHAR(60)      DEFAULT NULL COMMENT '对方账号；客户往账业务对应传票上记载的最终交易对手信息。1. 现转标志为“转”时，交易对手信息必填，不可为空。2. 该笔明细交易是转账交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户。3. 交易对手是第三方支付平台账号的，对方账号填报为交易对手第三方支付账号，对方户名填报为交易对手的第三方支付户名，对方行名填报为第三方支付平台名称，对方行号允许为空。4. 对于代收、代扣、代缴等交易的，对方账号和对方户名必须填实际收款人或付款人，不可填中间过渡账户或清算账户；对于代发等代付业务，交易对手为多个的，允许交易对手可以登记为中间过渡账户。5. 对方账号与对方户名必须一致，对应同一实体。6. 若对方账户是境内银行机构开立的账户，则对方行号必须是12位人行支付行号，对方行名必须是与人行支付行号对应的银行机构名称。分支机构如没有人行支付行号，可填写最近的上一级管理机构支付行号。各行应从官方渠道获得一份官方发布的人行支付行号及行名字典表，确保对方行号填写的人行支付行号与对方行名保持一致。7. 贷款还息、贷款还本、手续费、系统转存等交易，交易对手填实际转入的信贷分户账或内部分户账，并在摘要中注明，不可为空。',
  `DFXM`                   VARCHAR(450)     DEFAULT NULL COMMENT '对方行名；客户往账业务对应传票上记载的最终交易对手信息。1. 现转标志为“转”时，交易对手信息必填，不可为空。2. 该笔明细交易是转账交易的，对方账号和对方户名必须填实际收款人，不可填中间过渡账户或清算账户。3. 交易对手是第三方支付平台账号的，对方账号填报为交易对手第三方支付账号，对方户名填报为交易对手的第三方支付户名，对方行名填报为第三方支付平台名称，对方行号允许为空。4. 对于代收、代扣、代缴等交易的，对方账号和对方户名必须填实际收款人或付款人，不可填中间过渡账户或清算账户；对于代发等代付业务，交易对手为多个的，允许交易对手可以登记为中间过渡账户。5. 对方账号与对方户名必须一致，对应同一实体。6. 若对方账户是境内银行机构开立的账户，则对方行号必须是12位人行支付行号，对方行名必须是与人行支付行号对应的银行机构名称。分支机构如没有人行支付行号，可填写最近的上一级管理机构支付行号。各行应从官方渠道获得一份官方发布的人行支付行号及行名字典表，确保对方行号填写的人行支付行号与对方行名保持一致。7. 贷款还息、贷款还本、手续费、系统转存等交易，交易对手填实际转入的信贷分户账或内部分户账，并在摘要中注明，不可为空。',
  `ZY`                     VARCHAR(600)     DEFAULT NULL COMMENT '摘要',
  `FY`                     VARCHAR(600)     DEFAULT NULL COMMENT '附言',
  `JYQD`                   VARCHAR(60)      DEFAULT NULL COMMENT '交易渠道；交易类型为三方支付的，以“三方支付-XX”填报，其中“XX”为第三方支付平台名称。',
  `JYGYH`                  VARCHAR(30)      DEFAULT NULL COMMENT '交易柜员号；关联数据项：柜员表.柜员号，自动办理的柜员号允许为空。',
  `BBZ`                    VARCHAR(600)     DEFAULT NULL COMMENT '备注；描述其他字段未能详尽说明的情况，或标注对本条报送记录的特殊说明（如视需要可用于说明各种不满足检核规则的例外情况：客户信息表中可标注“境外客户”“客户已工商注销”“客户名下账户均已管控”，信贷分户账中可标注“线上化业务”“自助类贷款”等）。不同备注事项用英文半角分号隔开。',
  `MACDZ`                  VARCHAR(60)      DEFAULT NULL COMMENT 'MAC地址；若交易渠道为网银、手机银行，需填写交易发起终端的设备地址，其他情况允许为空。',
  `DFKHLB`                 VARCHAR(6)       DEFAULT NULL COMMENT '对方客户类别',
  `ZHMC`                   VARCHAR(450)     DEFAULT NULL COMMENT '账户名称'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='对公存款分户账明细记录';
